import{_ as o,C as c,o as a,c as u,a5 as p,b as l,w as s,a as i,E as r,a4 as t}from"./chunks/framework.gGRxziV4.js";const g=JSON.parse('{"title":"06 - Continuous Learning：让 AI 不再\\"失忆\\"","description":"","frontmatter":{},"headers":[],"relativePath":"08-ECC教程/06-Continuous-Learning.md","filePath":"08-ECC教程/06-Continuous-Learning.md","lastUpdated":null}'),b={name:"08-ECC教程/06-Continuous-Learning.md"};function A(d,n,E,m,h,q){const e=c("Mermaid");return a(),u("div",null,[n[3]||(n[3]=p(`<h1 id="_06-continuous-learning-让-ai-不再-失忆" tabindex="-1">06 - Continuous Learning：让 AI 不再&quot;失忆&quot; <a class="header-anchor" href="#_06-continuous-learning-让-ai-不再-失忆" aria-label="Permalink to &quot;06 - Continuous Learning：让 AI 不再&quot;失忆&quot;&quot;">​</a></h1><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>每次新 session，AI 就失忆了。你纠正过 TA 的错误，下次 TA 还会犯。Continuous Learning 就是解决这个问题的——让 AI 从你的行为中学习，把教训固化下来。</p><hr><h2 id="真实痛点-你在同一个坑里反复教-ai" tabindex="-1">真实痛点：你在同一个坑里反复教 AI <a class="header-anchor" href="#真实痛点-你在同一个坑里反复教-ai" aria-label="Permalink to &quot;真实痛点：你在同一个坑里反复教 AI&quot;">​</a></h2><p>来看一个你大概率遇到过的场景：</p><blockquote><p>第 1 次：你写了一个 <code>data</code> 变量，AI 帮你改成了 <code>userData</code>，你说&quot;对，就该这样&quot;。 第 2 次：AI 自己写了一个 <code>data</code> 变量。你说：&quot;不是说过用 <code>userData</code> 吗？&quot; 第 3 次：AI 又写了 <code>data</code>。你说：&quot;😤&quot; 第 4 次：AI 终于记住了。 ……然后你开了一新 session，AI 又回到了第 1 次的状态。</p></blockquote><p><strong>为什么会这样？</strong> 因为 AI 的对话是&quot;一次性&quot;的——每次新 session，TA 的记忆从零开始。你上次纠正的东西，没有被持久化。就像一个每次上班都失忆的实习生，你每天都要重新教一遍。</p><p>这个问题有多烦？想象一下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你每天的工作状态：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  早上：纠正 AI 的变量命名      → AI 说&quot;好的&quot;</span></span>
<span class="line"><span>  上午：纠正 AI 的错误处理方式   → AI 说&quot;好的&quot;</span></span>
<span class="line"><span>  下午：纠正 AI 的测试写法      → AI 说&quot;好的&quot;</span></span>
<span class="line"><span>  第二天早上：一切归零，重新来过  → AI 说&quot;好的&quot;（但其实全忘了）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>你的&quot;教学时间&quot;不断被浪费。</strong> Continuous Learning 就是要终结这种浪费。</p><hr><h2 id="核心设计-从观察到直觉-不是存对话" tabindex="-1">核心设计：从观察到直觉，不是存对话 <a class="header-anchor" href="#核心设计-从观察到直觉-不是存对话" aria-label="Permalink to &quot;核心设计：从观察到直觉，不是存对话&quot;">​</a></h2><p>你可能想：直接把对话记录存下来不就行了？下次加载回来不就记得了？</p><p>不行。原因有三：</p><ol><li><strong>太冗余</strong> — 一天的对话可能有几万字，大部分是无关的，真正要记住的就几条</li><li><strong>隐私风险</strong> — 对话里可能有敏感信息，全部存下来不安全</li><li><strong>找不到重点</strong> — AI 重新读一遍对话，也不知道&quot;哪些是重点纠正&quot;</li></ol><p><strong>所以 Continuous Learning 用的是&quot;Instinct&quot;（直觉）——提炼后的模式，不是原始对话。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始对话（存下来不好）：</span></span>
<span class="line"><span>─────────────────────</span></span>
<span class="line"><span>你：这个变量用 userData</span></span>
<span class="line"><span>AI：好的</span></span>
<span class="line"><span>你：这个也用 userData</span></span>
<span class="line"><span>AI：好的</span></span>
<span class="line"><span>你：还有这个</span></span>
<span class="line"><span>AI：好的</span></span>
<span class="line"><span>……（几千字对话）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>提炼后的 Instinct（存这个就好）：</span></span>
<span class="line"><span>──────────────────────────────</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;pattern&quot;: &quot;变量命名偏好&quot;,</span></span>
<span class="line"><span>  &quot;rule&quot;: &quot;用描述性名称，不要用 data/tmp&quot;,</span></span>
<span class="line"><span>  &quot;confidence&quot;: &quot;高&quot;,</span></span>
<span class="line"><span>  &quot;source&quot;: &quot;5 次纠正&quot;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><p><strong>只存&quot;什么情况下应该怎么做&quot;，不存原始对话。</strong> 安全、高效、精准。</p>`,19)),(a(),l(t,null,{default:s(()=>[r(e,{id:"mermaid-65",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20CONV%5B%22%F0%9F%92%AC%20%E5%8E%9F%E5%A7%8B%E5%AF%B9%E8%AF%9D%5Cn%E5%87%A0%E4%B8%87%E5%AD%97%5Cn%E5%8C%85%E5%90%AB%E9%9A%90%E7%A7%81%5Cn%E5%A4%A7%E9%83%A8%E5%88%86%E6%97%A0%E5%85%B3%22%5D%0A%20%20%20%20INST%5B%22%F0%9F%92%A1%20Instinct%5Cn%E6%8F%90%E7%82%BC%E5%90%8E%E7%9A%84%E6%A8%A1%E5%BC%8F%5Cn%E5%8F%AA%E5%AD%98%E8%A7%84%E5%88%99%5Cn%E5%AE%89%E5%85%A8%E4%B8%94%E9%AB%98%E6%95%88%22%5D%0A%0A%20%20%20%20CONV%20-.-%3E%7C%22%E5%A4%AA%E5%86%97%E4%BD%99%5Cn%E9%9A%90%E7%A7%81%E9%A3%8E%E9%99%A9%5Cn%E6%89%BE%E4%B8%8D%E5%88%B0%E9%87%8D%E7%82%B9%22%7C%20X%5B%22%E2%9D%8C%20%E4%B8%8D%E9%80%82%E5%90%88%E5%AD%98%22%5D%0A%20%20%20%20CONV%20--%3E%7C%22%E6%8F%90%E7%82%BC%22%7C%20INST%0A%0A%20%20%20%20style%20CONV%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20INST%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20X%20fill%3A%239e9e9e%2Ccolor%3A%23fff%0A"})]),fallback:s(()=>[...n[0]||(n[0]=[i(" Loading... ",-1)])]),_:1})),n[4]||(n[4]=p(`<hr><h2 id="完整流程-从观察到进化" tabindex="-1">完整流程：从观察到进化 <a class="header-anchor" href="#完整流程-从观察到进化" aria-label="Permalink to &quot;完整流程：从观察到进化&quot;">​</a></h2><p>Continuous Learning 的完整流程分为四步，就像教小孩做家务：</p><h3 id="第-1-步-观察-observation" tabindex="-1">第 1 步：观察（Observation） <a class="header-anchor" href="#第-1-步-观察-observation" aria-label="Permalink to &quot;第 1 步：观察（Observation）&quot;">​</a></h3><p>AI 在跟你互动时，默默观察你的行为模式。你纠正了一次，TA 记一次。但这时候还只是&quot;看到了&quot;，不一定会记住。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>观察 #1：用户把 data 改成了 userData    → &quot;看到了&quot;</span></span>
<span class="line"><span>观察 #2：用户又把 data 改成了 userData  → &quot;有点意思&quot;</span></span>
<span class="line"><span>观察 #3：用户又改了                    → &quot;嗯，可能是偏好&quot;</span></span>
<span class="line"><span>观察 #4：用户又改了                    → &quot;这很可能是习惯&quot;</span></span>
<span class="line"><span>观察 #5：用户又改了                    → &quot;非常确定了&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="第-2-步-提取模式-pattern-extraction" tabindex="-1">第 2 步：提取模式（Pattern Extraction） <a class="header-anchor" href="#第-2-步-提取模式-pattern-extraction" aria-label="Permalink to &quot;第 2 步：提取模式（Pattern Extraction）&quot;">​</a></h3><p>当一个行为重复出现足够多次，AI 会提取出一个&quot;模式&quot;——不记具体对话，只记&quot;用户在什么情况下会怎么做&quot;。</p><h3 id="第-3-步-信心度评估-confidence-scoring" tabindex="-1">第 3 步：信心度评估（Confidence Scoring） <a class="header-anchor" href="#第-3-步-信心度评估-confidence-scoring" aria-label="Permalink to &quot;第 3 步：信心度评估（Confidence Scoring）&quot;">​</a></h3><p>不是所有学到的模式都可靠。有些是偶然，有些是规律。</p><p><strong>这就是 Confidence Scoring 的价值——帮你区分&quot;这个建议可以信&quot;还是&quot;仅供参考&quot;。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>信心度分级：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  观察 1 次，一致率 100%  → ★☆☆☆☆ 很低，可能是巧合</span></span>
<span class="line"><span>  观察 3 次，一致率 100%  → ★★★☆☆ 中等，值得关注</span></span>
<span class="line"><span>  观察 5 次，一致率 100%  → ★★★★☆ 高，基本确定</span></span>
<span class="line"><span>  观察 10 次，一致率 90%  → ★★★★★ 很高，完全信任</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>为什么需要这个？</strong> 因为不是所有行为模式都值得记住。比如你某天特别累，连续三次把变量命名弄得很随意——AI 不应该学这个&quot;坏习惯&quot;。Confidence Scoring 通过&quot;足够多次观察 + 高一致率&quot;来过滤掉偶然行为。</p><h3 id="第-4-步-进化-evolution" tabindex="-1">第 4 步：进化（Evolution） <a class="header-anchor" href="#第-4-步-进化-evolution" aria-label="Permalink to &quot;第 4 步：进化（Evolution）&quot;">​</a></h3><p>信心度够高之后，直觉会&quot;进化&quot;成一个 Skill 或者一条 Rule，以后自动执行。</p>`,15)),(a(),l(t,null,{default:s(()=>[r(e,{id:"mermaid-105",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20USE%5B%22%F0%9F%8E%AE%20%E4%BD%A0%E7%9A%84%E6%97%A5%E5%B8%B8%E4%BD%BF%E7%94%A8%5Cn%E5%86%99%E4%BB%A3%E7%A0%81%E3%80%81%E6%94%B9%E4%BB%A3%E7%A0%81%E3%80%81%E7%BA%A0%E6%AD%A3%E3%80%81%E7%A1%AE%E8%AE%A4%22%5D%0A%20%20%20%20OBS%5B%22%F0%9F%91%81%EF%B8%8F%20%E6%8D%95%E8%8E%B7%E8%A7%82%E5%AF%9F%5Cn%E7%94%A8%E6%88%B7%E7%BA%A0%E6%AD%A3%E4%BA%86%20data%20%E2%86%92%20userData%5Cn%E7%AC%AC%201%20%E6%AC%A1%E2%80%A6%E7%AC%AC%203%20%E6%AC%A1%E2%80%A6%E7%AC%AC%205%20%E6%AC%A1%22%5D%0A%20%20%20%20PAT%5B%22%F0%9F%94%8D%20%E6%8F%90%E5%8F%96%E6%A8%A1%E5%BC%8F%5Cn%E8%BF%99%E4%B8%AA%E7%BA%A0%E6%AD%A3%E5%87%BA%E7%8E%B0%E4%BA%86%E5%A4%9A%E6%AC%A1%5Cn%E7%9C%8B%E8%B5%B7%E6%9D%A5%E6%98%AF%E5%9B%BA%E5%AE%9A%E5%81%8F%E5%A5%BD%22%5D%0A%20%20%20%20CONF%5B%22%F0%9F%93%8A%20%E4%BF%A1%E5%BF%83%E5%BA%A6%E8%AF%84%E4%BC%B0%5Cn5%20%E6%AC%A1%E8%A7%82%E5%AF%9F%EF%BC%8C%E4%B8%80%E8%87%B4%E7%8E%87%20100%25%5Cn%E4%BF%A1%E5%BF%83%E5%BA%A6%EF%BC%9A%E9%AB%98%20%E2%9C%85%22%5D%0A%20%20%20%20EVO%5B%22%F0%9F%93%96%20%E8%BF%9B%E5%8C%96%E4%B8%BA%E8%A7%84%E5%88%99%5Cn%E5%86%99%E5%85%A5%E9%A1%B9%E7%9B%AE%E7%9A%84%20Skill%20%2F%20Rule%5Cn%E4%BB%A5%E5%90%8E%E8%87%AA%E5%8A%A8%E9%81%B5%E5%AE%88%22%5D%0A%0A%20%20%20%20USE%20--%3E%20OBS%20--%3E%20PAT%20--%3E%20CONF%20--%3E%20EVO%0A%0A%20%20%20%20style%20USE%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20OBS%20fill%3A%23ffa726%2Ccolor%3A%23fff%0A%20%20%20%20style%20PAT%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20CONF%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20EVO%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A"})]),fallback:s(()=>[...n[1]||(n[1]=[i(" Loading... ",-1)])]),_:1})),n[5]||(n[5]=p(`<p><strong>整个流程是全自动的。你不需要做任何额外的事——正常用就好。</strong></p><hr><h2 id="为什么-v2-要做-project-scoped-项目隔离" tabindex="-1">为什么 v2 要做 Project-Scoped（项目隔离）？ <a class="header-anchor" href="#为什么-v2-要做-project-scoped-项目隔离" aria-label="Permalink to &quot;为什么 v2 要做 Project-Scoped（项目隔离）？&quot;">​</a></h2><p>这是 Continuous Learning 在 v2 中最重要的升级。</p><p><strong>你在 React 项目学到的&quot;用 hooks 不用 class&quot;，不应该影响你的 Python 项目。</strong></p><p>为什么？因为不同项目的规矩完全不同：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>项目 A（React 前端）</span></span>
<span class="line"><span>┌──────────────────────────────┐</span></span>
<span class="line"><span>│ 学到的：                       │</span></span>
<span class="line"><span>│ - 组件用 PascalCase           │</span></span>
<span class="line"><span>│ - 用函数组件，不用类组件        │</span></span>
<span class="line"><span>│ - CSS 用 Tailwind             │</span></span>
<span class="line"><span>│ - 提交前跑 npm test           │</span></span>
<span class="line"><span>└──────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>项目 B（Python 后端）</span></span>
<span class="line"><span>┌──────────────────────────────┐</span></span>
<span class="line"><span>│ 学到的：                       │</span></span>
<span class="line"><span>│ - 函数用 snake_case           │</span></span>
<span class="line"><span>│ - 用 pytest，不用 unittest    │</span></span>
<span class="line"><span>│ - 类型注解必须完整             │</span></span>
<span class="line"><span>│ - 提交前跑 pytest + mypy      │</span></span>
<span class="line"><span>└──────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果 A 的规矩带到 B 项目 → Python 里出现 PascalCase 函数名 → 乱套了！</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p><strong>Project-Scoped 的本质是&quot;上下文隔离&quot;。</strong> 每个项目有自己的&quot;学习成果&quot;，互不干扰。</p><p>这个设计思想其实很常见——就像你不会把&quot;在家穿拖鞋&quot;的习惯带到办公室去一样。不同的环境，不同的规矩。</p>`,9)),(a(),l(t,null,{default:s(()=>[r(e,{id:"mermaid-129",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20PROJA%5B%22%E9%A1%B9%E7%9B%AE%20A%EF%BC%88React%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20LA1%5B%22PascalCase%20%E7%BB%84%E4%BB%B6%22%5D%0A%20%20%20%20%20%20%20%20LA2%5B%22%E5%87%BD%E6%95%B0%E7%BB%84%E4%BB%B6%E4%BC%98%E5%85%88%22%5D%0A%20%20%20%20%20%20%20%20LA3%5B%22Tailwind%20CSS%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20PROJB%5B%22%E9%A1%B9%E7%9B%AE%20B%EF%BC%88Python%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20LB1%5B%22snake_case%20%E5%87%BD%E6%95%B0%22%5D%0A%20%20%20%20%20%20%20%20LB2%5B%22pytest%20%E6%B5%8B%E8%AF%95%22%5D%0A%20%20%20%20%20%20%20%20LB3%5B%22%E7%B1%BB%E5%9E%8B%E6%B3%A8%E8%A7%A3%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20PROJA%20-.-%20PROJB%0A%0A%20%20%20%20style%20PROJA%20fill%3A%23e3f2fd%2Cstroke%3A%2342a5f5%0A%20%20%20%20style%20PROJB%20fill%3A%23f3e5f5%2Cstroke%3A%23ab47bc%0A%20%20%20%20style%20LA1%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20LA2%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20LA3%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20LB1%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A%20%20%20%20style%20LB2%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A%20%20%20%20style%20LB3%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A"})]),fallback:s(()=>[...n[2]||(n[2]=[i(" Loading... ",-1)])]),_:1})),n[6]||(n[6]=p(`<hr><h2 id="continuous-learning-vs-rules-有什么区别" tabindex="-1">Continuous Learning vs Rules：有什么区别？ <a class="header-anchor" href="#continuous-learning-vs-rules-有什么区别" aria-label="Permalink to &quot;Continuous Learning vs Rules：有什么区别？&quot;">​</a></h2><p>你可能会问：这跟 Rules 系统（下一章讲的）有什么不同？</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Rules（规则）              Continuous Learning（学习）</span></span>
<span class="line"><span>══════════                ══════════════════════════</span></span>
<span class="line"><span>你主动写的                  AI 自动发现的</span></span>
<span class="line"><span>明确的、固定的              隐式的、会变化的</span></span>
<span class="line"><span>全局生效（跨项目）           项目隔离</span></span>
<span class="line"><span>&quot;代码不能超过 800 行&quot;       &quot;这个用户喜欢用 const&quot;</span></span>
<span class="line"><span>像法律                     像习惯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><strong>一句话：Rules 是你定的&quot;法律&quot;，Learning 是 AI 养成的&quot;习惯&quot;。</strong></p><p>两者互补：Rules 是骨架（底线要求），Learning 是血肉（个性化偏好）。光有 Rules 没有 Learning，AI 就是个&quot;标准化产品&quot;；光有 Learning 没有 Rules，AI 可能学歪。</p><hr><h2 id="安全机制-ai-学歪了怎么办" tabindex="-1">安全机制：AI 学歪了怎么办？ <a class="header-anchor" href="#安全机制-ai-学歪了怎么办" aria-label="Permalink to &quot;安全机制：AI 学歪了怎么办？&quot;">​</a></h2><p>你可能担心：AI 自己&quot;学习&quot;的规则，会不会学歪了？</p><p>系统有几层保障：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>安全机制</span></span>
<span class="line"><span>════════</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 信心度门槛</span></span>
<span class="line"><span>   不是每次观察都记住，需要达到一定次数和一致性</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 项目隔离</span></span>
<span class="line"><span>   A 项目学的不会影响 B 项目</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 会衰减</span></span>
<span class="line"><span>   你改变了行为，旧的 instinct 信心度会自然下降</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 不覆盖 Rules</span></span>
<span class="line"><span>   Learning 是补充，不会覆盖你明确设置的 Rules</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 可查看</span></span>
<span class="line"><span>   /instinct-status 让你随时看 AI 学到了什么</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p><strong>举个衰减的例子：</strong></p><blockquote><p>你之前一直用 <code>var</code>，AI 学会了&quot;用户喜欢 var&quot;（信心度 ★★★★☆）。 后来你开始用 <code>const</code>，AI 观察到你的偏好变了。 经过几次新观察，旧 instinct 的信心度从 ★★★★☆ 降到 ★★☆☆☆。 新 instinct &quot;用户喜欢 const&quot;的信心度升到 ★★★★☆。 旧的自然被淘汰。</p></blockquote><p><strong>这就像人的习惯一样——旧习惯会被新习惯取代，而不是永远保留。</strong></p><hr><h2 id="你能看到-ai-学到了什么吗" tabindex="-1">你能看到 AI 学到了什么吗？ <a class="header-anchor" href="#你能看到-ai-学到了什么吗" aria-label="Permalink to &quot;你能看到 AI 学到了什么吗？&quot;">​</a></h2><p>能！系统提供了 <code>/instinct-status</code> 命令：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你输入：/instinct-status</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI 输出：</span></span>
<span class="line"><span>┌──────────────────────────────────────────┐</span></span>
<span class="line"><span>│  📊 学习状态报告                          │</span></span>
<span class="line"><span>├──────────────────────────────────────────┤</span></span>
<span class="line"><span>│  项目：my-react-app                       │</span></span>
<span class="line"><span>│                                          │</span></span>
<span class="line"><span>│  已学 Instincts（3 条）：                  │</span></span>
<span class="line"><span>│                                          │</span></span>
<span class="line"><span>│  1. 变量命名偏好                           │</span></span>
<span class="line"><span>│     内容：优先使用描述性名称                 │</span></span>
<span class="line"><span>│     信心度：★★★★☆（高）                   │</span></span>
<span class="line"><span>│     来源：5 次纠正                         │</span></span>
<span class="line"><span>│                                          │</span></span>
<span class="line"><span>│  2. 提交前验证                             │</span></span>
<span class="line"><span>│     内容：每次提交前必须跑测试和 lint        │</span></span>
<span class="line"><span>│     信心度：★★★★★（很高）                 │</span></span>
<span class="line"><span>│     来源：8 次确认                         │</span></span>
<span class="line"><span>│                                          │</span></span>
<span class="line"><span>│  3. 组件拆分风格                           │</span></span>
<span class="line"><span>│     内容：超过 200 行的组件应该拆分          │</span></span>
<span class="line"><span>│     信心度：★★★☆☆（中等）                │</span></span>
<span class="line"><span>│     来源：3 次纠正                         │</span></span>
<span class="line"><span>└──────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br></div></div><p>这个命令让你随时了解 AI &quot;偷偷&quot;学会了什么，透明可控。</p><hr><h2 id="好处和代价" tabindex="-1">好处和代价 <a class="header-anchor" href="#好处和代价" aria-label="Permalink to &quot;好处和代价&quot;">​</a></h2><p><strong>好处：</strong></p><ul><li>🧠 AI 越用越懂你，纠正过的错误不会再犯</li><li>🔒 只存提炼后的模式，不存原始对话，隐私安全</li><li>📊 信心度机制，过滤偶然行为</li><li>🏗️ 项目隔离，不同项目规矩不混淆</li><li>🔄 会衰减，适应你的变化</li></ul><p><strong>代价：</strong></p><ul><li>⏳ 需要一定使用量才能形成可靠直觉（不是用一次就生效）</li><li>📏 提炼可能丢失一些上下文细节</li><li>🎯 高度个性化的规则可能不适合团队共享</li></ul><hr><h2 id="对你自己的项目的启发" tabindex="-1">对你自己的项目的启发 <a class="header-anchor" href="#对你自己的项目的启发" aria-label="Permalink to &quot;对你自己的项目的启发&quot;">​</a></h2><ol><li><strong>AI 应该从交互中学习</strong> — 如果你的 AI 产品每次对话都从零开始，用户体验会很差。想办法把&quot;学到的教训&quot;持久化</li><li><strong>存提炼后的模式，不是原始数据</strong> — 这既保护隐私，又提高效率。原始对话太冗余，提炼后的规则才值钱</li><li><strong>信心度是个好工具</strong> — 不是所有观察都可靠，用&quot;多次观察 + 一致率&quot;来过滤噪音</li><li><strong>上下文隔离很重要</strong> — 不同项目/场景学到的东西不应该互相污染</li></ol><blockquote><p>💡 <strong>下一步</strong>：正常使用你的 AI 项目一两周，然后试试 <code>/instinct-status</code>，看看 TA &quot;偷偷&quot;学会了什么。你可能会很惊讶——TA 比你想象的更了解你的习惯。</p></blockquote>`,29))])}const C=o(b,[["render",A]]);export{g as __pageData,C as default};
